function openRobotPosition(signal){
  const r=state.robot;if(r.investment>availablePaperBalance()){r.active=false;showToast('Saldo insuficiente para nova entrada',`Disponível: ${usdt(availablePaperBalance())}. Reduza o capital por operação.`,'exit');renderRobotUI(signal);return}const s=strategies[r.strategy]||strategies.intraday,entry=state.currentPrice,fees=tradingCosts().total,target=entry*(1+fees+s.target/100),stop=entry*(1-Math.max(.001,s.risk/100-fees)),breakEven=entry*(1+fees),protection=r.strategy==='boost'?'breakeven':'technical';r.position={symbol:state.asset,marketSymbol:state.marketSymbol,owner:'robot',entry,target,stop,breakEven,protection,fees,investment:r.investment,strategy:s.label,score:signal.score,riskPercent:s.risk,openedAt:Date.now()};r.stopRequested=false;r.lastActionAt=Date.now();state.order={active:true,entry,target,stop,breakEven,protection,fees,investment:r.investment,owner:'robot',symbol:state.asset,strategy:s.label,score:signal.score,riskPercent:s.risk,openedAt:r.position.openedAt,marketSymbol:state.marketSymbol,targetPercent:s.target,trailing:false,peakPrice:entry,approachAlerted:false,targetAlerted:false};$('#entryPrice').textContent=formatPrice(entry);$('#targetPrice').textContent=formatPrice(target);$('#stopPrice').textContent=r.strategy==='boost'?`0×0 · ${formatPrice(breakEven)}`:formatPrice(stop);$('#targetPercentLabel').textContent=`+${s.target.toFixed(2).replace('.',',')}%`;$('.status-pill').textContent='● Robô em operação';$('#exitTradeBtn').disabled=false;$('#closeTradeBtn').disabled=false;addNotification('Entrada automática registrada',`${displayPair()} · ${s.label} · confiança ${signal.score}/100.`);showToast(r.strategy==='boost'?'Entrada Boost registrada':'Entrada automática registrada',`${displayPair()} · confiança ${signal.score}/100.`);updateOperation();renderRobotUI(signal);drawChart()
}
function closeRobotPosition(reason){
  const r=state.robot,p=r.position;if(!p)return false;const currentNet=robotNet(p);if(r.strategy==='boost'&&currentNet<-1e-8){r.stopRequested=r.stopRequested||/desativado|parar|manual/i.test(String(reason));showToast('Trava 0×0 ativa',`A saída ficou pendente até ${displayPair()} recuperar o resultado líquido para 0,00%.`,'exit');renderRobotUI();drawChart();return false}let record;try{record=settleTrade(p,state.currentPrice,reason)}catch(error){showToast('Falha ao encerrar',error.message,'exit');return false}r.trades.unshift(record);r.sessionProfit+=record.value;r.position=null;r.stopRequested=false;r.lastActionAt=Date.now();state.order.active=false;$('.status-pill').textContent='● Encerrada pelo robô';$('#exitTradeBtn').disabled=true;$('#closeTradeBtn').disabled=true;if(r.trades.length>=r.maxTrades)r.active=false;showToast(record.net>0?'Saída automática com lucro':'Saída automática protegida',`${reason} · ${record.net>=0?'+':''}${record.net.toFixed(2).replace('.',',')}% líquido.`,record.net>=0?'success':'exit');renderRobotUI();drawChart();return true
}
function runRobot(){const r=state.robot,signal=calculateRobotSignal(),s=signal.strategy;r.lastScore=signal.score;renderRobotUI(signal);if((!r.active&&!r.position)||state.marketChanging)return;if(r.position){const p=r.position,net=robotNet(p);if(r.strategy==='boost'){if(net>=s.target)closeRobotPosition('Lucro Boost de +0,20% atingido');else if(net>=-1e-8&&(r.stopRequested||signal.score<=s.reversal))closeRobotPosition(r.stopRequested?'Saída protegida solicitada pelo usuário':'Reversão encerrada em 0×0');else{updateForecastLabel();drawChart()}return}if(net>=s.target)closeRobotPosition('Meta da estratégia atingida');else if(state.currentPrice<=p.stop)closeRobotPosition('Stop de proteção atingido');else if(signal.score<=s.reversal)closeRobotPosition('Reversão do sinal detectada');return}if(!r.active)return;if(r.trades.length>=r.maxTrades){r.active=false;renderRobotUI(signal);showToast('Limite da sessão atingido',`${r.maxTrades} operações automáticas concluídas.`);return}if(Date.now()-r.lastActionAt<s.cooldown)return;if(signal.score>=s.score)openRobotPosition(signal)}
function stopRobot(){const r=state.robot,p=r.position;if(p&&r.strategy==='boost'&&robotNet(p)<-1e-8){r.stopRequested=true;r.active=true;showToast('Parada programada em 0×0',`O Boost não abrirá outra ordem e encerrará esta posição assim que não houver perda.`,'exit');renderRobotUI();return}const hadPosition=!!p;r.active=false;if(hadPosition)closeRobotPosition('Robô desativado pelo usuário');else{renderRobotUI();showToast('Robô Trade desativado','Nenhuma nova entrada será registrada.','exit')}}
function openTrade(){if(state.robot.active||state.robot.starting){showToast('Robô Trade ativo','Pause o robô antes de registrar uma entrada manual.','exit');return}if(state.order.active){showToast('Operação em andamento','Registre a saída antes de criar uma nova entrada.','exit');return}const balance=availablePaperBalance();if(balance<10){showToast('Saldo insuficiente','Reinicie a carteira com pelo menos 10 USD equivalentes para continuar.','exit');return}const investment=$('#investment'),displayBalance=fromBaseAmount(balance);investment.max=String(displayBalance);if(Number(investment.value)>displayBalance)investment.value=String(displayBalance.toFixed(2));calcTarget();const d=$('#tradeModal');if(typeof d.showModal==='function')d.showModal()}
function numberInRange(value,fallback,min,max){const number=Number(value);return Number.isFinite(number)?Math.min(max,Math.max(min,number)):fallback}
function tradingCosts(){const buy=numberInRange($('#buyFee').value,.1,0,20),sell=numberInRange($('#sellFee').value,.1,0,20),slippage=numberInRange($('#slippage').value,.05,0,20);return{buy,sell,slippage,total:(buy+sell+2*slippage)/100}}
function calcTarget(){const entry=state.currentPrice,costs=tradingCosts(),target=numberInRange($('#profitTarget').value,2,.01,100)/100,invest=numberInRange(toBaseAmount($('#investment').value),0,0,1000000000),price=entry*(1+costs.total+target);$('#modalTarget').textContent=formatPrice(price);$('#expectedProfit').textContent=fmt(invest*target);return price}
function showToast(title,text,kind='success'){const toast=$('#toast');toast.querySelector('span').textContent=kind==='exit'?'↘':'✓';toast.querySelector('strong').textContent=title;toast.querySelector('small').textContent=text;toast.classList.add('show');clearTimeout(showToast.timer);showToast.timer=setTimeout(()=>toast.classList.remove('show'),3000)}
function showGoalAlert(hit=false){const alert=$('#goalAlert');alert.classList.toggle('hit',hit);$('#goalAlertLabel').textContent=hit?'META ATINGIDA':'ALERTA DE PROXIMIDADE';$('#goalAlertTitle').textContent=hit?'Lucro líquido atingido':'Preço próximo ao alvo';$('#goalAlertText').textContent=hit?'A operação pode ser encerrada conforme o objetivo escolhido.':'Falta menos de 0,20% para o lucro definido na ordem.';addNotification(hit?'Meta líquida atingida':'Preço próximo ao alvo',`${displayPair()} · ${formatPrice(state.currentPrice)}.`);const old=alert.querySelector(':scope>i'),timer=old.cloneNode();old.replaceWith(timer);alert.classList.add('show');clearTimeout(showGoalAlert.timer);showGoalAlert.timer=setTimeout(()=>alert.classList.remove('show'),3000)}
function updateOperation(){
  if(!state.order.active)return;
  if(state.order.trailing){state.order.peakPrice=Math.max(Number(state.order.peakPrice)||state.currentPrice,state.currentPrice);const risk=Math.max(.1,Number(state.order.riskPercent)||1.5),distance=Math.max(.001,risk/100-state.order.fees),trailingStop=state.order.peakPrice*(1-distance);if(trailingStop>state.order.stop){state.order.stop=trailingStop;$('#stopPrice').textContent=formatPrice(trailingStop)}}
  if(state.order.owner==='manual'&&state.currentPrice<=state.order.stop){closeActiveOrder(state.order.trailing?'Trailing stop atingido':'Stop técnico atingido');return}
  const gross=(state.currentPrice/state.order.entry-1)*100,net=gross-state.order.fees*100,targetPct=Math.max(.01,Number(state.order.targetPercent)||numberInRange($('#profitTarget').value,2,.01,100)),remaining=Math.max(0,targetPct-net),progress=Math.max(0,Math.min(100,net/targetPct*100));
  $('#grossProfit').textContent=(gross>=0?'+':'')+gross.toFixed(2).replace('.',',')+'%';$('#grossProfit').className=gross>=0?'positive':'negative';$('#estimatedCosts').textContent=(state.order.fees*100).toFixed(2).replace('.',',')+'%';$('#netProfit').textContent=(net>=0?'+':'')+net.toFixed(2).replace('.',',')+'%';$('#netProfit').className=net>=0?'positive':'negative';$('#remainingProfit').textContent=remaining.toFixed(2).replace('.',',')+'%';$('#progressLabel').textContent=Math.round(progress)+'%';$('#goalProgress').style.width=progress+'%';$('#currentPin').style.left=progress+'%';
  const distance=(state.order.target-state.currentPrice)/state.order.target*100;if(distance<=.2&&distance>0&&!state.order.approachAlerted){state.order.approachAlerted=true;showGoalAlert(false)}if(state.currentPrice>=state.order.target&&!state.order.targetAlerted){state.order.targetAlerted=true;showGoalAlert(true)}
}
function selectStrategy(key){state.strategy=key;const s=strategies[key];$$('.strategy-card').forEach(c=>c.classList.toggle('active',c.dataset.strategy===key));$('#strategyScore').textContent=s.score+' / 100';$('#strategyRisk').textContent=s.risk.toFixed(1).replace('.',',')+'%';$('#strategyExposure').textContent=s.exposure}
function applyStrategy(){if(state.robot.active||state.robot.starting){$('#strategyModal').close();showToast('Robô Trade ativo','Pare o robô para trocar a estratégia principal.','exit');return}const s=strategies[state.strategy];$('#profitTarget').value=s.target;$('#maxRisk').value=s.risk;$('#targetPercentLabel').textContent='+'+s.target.toFixed(2).replace('.',',')+'%';state.timeframe=s.entry;$$('#timeframes button').forEach(b=>b.classList.toggle('active',b.textContent===s.entry));$('#activeStrategy').textContent=s.label+' · '+s.entry+' / '+s.confirm+' / '+s.trend;calcTarget();loadMarketCandles();$('#strategyModal').close();showToast('Estratégia aplicada',s.label+' ajustou gráfico, meta e risco.')}
function closeActiveOrder(reason='Saída manual registrada'){if(!state.order.active)return;if(state.order.owner==='robot'){closeRobotPosition(typeof reason==='string'?reason:'Saída manual registrada');return}let record;try{record=settleTrade(state.order,state.currentPrice,typeof reason==='string'?reason:'Saída manual registrada')}catch(error){showToast('Falha ao encerrar',error.message,'exit');return}state.order.active=false;state.order.trailing=false;$('.status-pill').textContent='● Encerrada';$('#exitTradeBtn').disabled=true;$('#closeTradeBtn').disabled=true;$('#trailingBtn').classList.remove('active');$('#trailingBtn').textContent='◇ Ativar trailing stop';showToast(record.net>=0?'Saída com lucro registrada':'Saída com perda registrada',`${record.net>=0?'+':''}${record.net.toFixed(2).replace('.',',')}% · ${signedUsdt(record.value)}.`,record.net>=0?'success':'exit');drawChart()}
