async function tick(){if(state.marketChanging)return;if(state.dataSource==='binance'){const refreshMs=state.robot.active&&state.robot.strategy==='boost'?4000:10000;if(state.liveRefreshing||Date.now()-state.lastLiveRefresh<refreshMs)return;state.liveRefreshing=true;state.lastLiveRefresh=Date.now();try{const quote=await fetchBinance(`/api/v3/ticker/price?symbol=${encodeURIComponent(state.marketSymbol)}`),price=Number(quote.price);if(!Number.isFinite(price)||price<=0)throw new Error('Preço inválido');state.liveFailures=0;state.currentPrice=price;candles.at(-1).close=price;candles.at(-1).high=Math.max(candles.at(-1).high,price);candles.at(-1).low=Math.min(candles.at(-1).low,price);$('#currentPrice').textContent=formatPrice(price);evaluatePriceAlerts();updateOperation();runRobot();drawChart()}catch(error){state.liveFailures+=1;runRobot();if(state.liveFailures>=3){state.dataSource='simulated';$('#statSource').textContent='Fallback local';showToast('Conexão instável','O preço continuará no modo simulado até selecionar o mercado novamente.','exit')}}finally{state.liveRefreshing=false}return}const pulse=(Math.random()-.46)*Math.max(state.currentPrice*.00018,.000001);state.currentPrice+=pulse;candles.at(-1).close=state.currentPrice;candles.at(-1).high=Math.max(candles.at(-1).high,state.currentPrice);candles.at(-1).low=Math.min(candles.at(-1).low,state.currentPrice);$('#currentPrice').textContent=formatPrice(state.currentPrice);evaluatePriceAlerts();updateOperation();runRobot();drawChart()}
